// // This module implements a combinational logic circuit that computes an output Y based on a combination of inputs. The module takes five input signals (A1, A2, A3, B1, B2) and processes them through two AND gates followed by an NAND gate. The first AND gate outputs a signal based on A1, A2, and A3, while the second AND gate processes inputs B1 and B2. The final output Y is determined by the logical NAND of these two AND gate outputs, with a buffer used to drive Y.
module top_module(
    // Inputs
    input A1,
    input A2,
    input A3,
    input B1,
    input B2,

    // Outputs
    output Y
);// Local signals
    wire nor0_out ;
    wire nor1_out ;
    wire or0_out_Y;

    //  Name  Output     Other arguments
    nor nor0 (nor0_out , A3, A1, A2        );
    nor nor1 (nor1_out , B1, B2            );
    or  or0  (or0_out_Y, nor1_out, nor0_out);
    buf buf0 (Y        , or0_out_Y         );

endmodule
